previewCss:
.darma-loader-darma-custom-342 {color: var(--loader-color, #9333ea);
  --loader-secondary-color: var(--loader-secondary-color, #f0abfc);
  --loader-bg: var(--loader-bg, #ffffff);
  height: 70px;
  aspect-ratio: 1;
  box-sizing: border-box;
  position: relative;
  mask:radial-gradient(#0000 47%,currentColor 48% 71%,#0000 72%) exclude,conic-gradient(currentColor 0 0) no-clip;
  animation: darma-loader-darma-custom-342-l11 1.5s linear infinite;
}.darma-loader-darma-custom-342:before {content: "";
  position: absolute;
  inset: 0 35% 70%;
  border-radius: 50%;
  background: currentColor;
  filter: blur(15px);
}@keyframes darma-loader-darma-custom-342-l11 {to {rotate: 1turn}}

